function toIDDate(s) { var p = s.split('-'); return parseInt(p[2], 10) + ' ' + BULAN_ID[parseInt(p[1], 10) - 1] + ' ' + p[0]; }
function fromIDDate(s) { var M = { januari: '01', februari: '02', maret: '03', april: '04', mei: '05', juni: '06', juli: '07', agustus: '08', september: '09', oktober: '10', november: '11', desember: '12' }; var p = s.toLowerCase().replace(/[^a-z0-9\s]/g, '').trim().split(/\s+/); if (p.length < 3) return ''; return p[2] + '-' + (M[p[1]] || '01') + '-' + p[0].padStart(2, '0'); }
function extractTime(s) { return (s || '').split(' ')[0]; }
function parseIDDate(s) { var p = s.toLowerCase().replace(/[^a-z0-9\s]/g, '').trim().split(/\s+/); if (p.length < 3) return 0; var d = parseInt(p[0], 10), m = BULAN_MAP[p[1]], y = parseInt(p[2], 10); if (isNaN(d) || isNaN(m) || isNaN(y)) return 0; return new Date(y, m, d).getTime(); }
function isFuture(s) { var t = parseIDDate(s); if (!t) return false; return t >= new Date(new Date().setHours(0, 0, 0, 0)).getTime(); }
function platformClass(p) { var m = { 'YouTube': 'youtube', 'TikTok': 'tiktok', 'Instagram': 'instagram', 'X (Twitter)': 'x-twitter', 'Facebook': 'facebook', 'Lainnya': 'lainnya' }; return m[p] || 'lainnya'; }
function todayStr() { var t = new Date(); return t.getFullYear() + '-' + String(t.getMonth() + 1).padStart(2, '0') + '-' + String(t.getDate()).padStart(2, '0'); }
function isToxic(text) { if (!text) return false; var lower = text.toLowerCase(); return TOXIC_WORDS.some(function (w) { return lower.indexOf(w) !== -1; }); }
function cleanHashtag(tag) { tag = tag.trim(); while (tag.startsWith('#')) tag = tag.substring(1); return tag.trim(); }

