function handleDrop(e, px) { e.preventDefault(); e.stopPropagation(); document.getElementById(px + 'UploadArea').classList.remove('dragover'); var file = e.dataTransfer.files[0]; if (!file || !file.type.startsWith('image/')) return; if (file.size > 5 * 1024 * 1024) { toast('Ukuran foto terlalu besar', 'error'); return; } var ph = document.getElementById(px + 'Placeholder'); ph.innerHTML = '<div class="spinner"></div>'; compressImageFile(file, 1200, 0.7).then(function (b64) { if (b64.length > 45000) { toast('Foto terlalu besar', 'error'); ph.innerHTML = buildUploadPlaceholderHTML(px); return; } if (px === 'p') { projectFotoBase64 = b64; } else if (px === 'ep') { editProjectFotoBase64 = b64; } showFotoPreview(px, b64); toast('Foto berhasil diunggah', 'success'); }).catch(function () { toast('Gagal memproses gambar', 'error'); ph.innerHTML = buildUploadPlaceholderHTML(px); }); }

