function updateJadwalFormUI(px) { var tipe = document.getElementById(px + 'Tipe').value; var tgl = document.getElementById(px + 'Tanggal').value; var gJam = document.getElementById(px + 'JamGroup'); var gUs = document.getElementById(px + 'UnitSongGroup'); var gSo = document.getElementById(px + 'SoGroup'); var gLink = document.getElementById(px + 'LinkGroup'); var lbl = document.getElementById(px + 'NamaLabel'); var isTema = isTemaType(tipe); var isDigital = (tipe === 'digital'); var isPast = false; if (tgl) { var today = new Date(); today.setHours(0, 0, 0, 0); var d = new Date(tgl + 'T00:00:00'); if (d < today) isPast = true; } if (isTema) lbl.textContent = 'Tema'; else lbl.textContent = 'Nama Kegiatan'; var showSoLink = isTema && !isPast; if (gSo) gSo.style.display = showSoLink ? '' : 'none'; if (gLink) gLink.style.display = showSoLink ? '' : 'none'; if (!showSoLink) { if (document.getElementById(px + 'So')) document.getElementById(px + 'So').value = ''; if (document.getElementById(px + 'Link')) document.getElementById(px + 'Link').value = ''; } if (isDigital) { if (gJam) gJam.style.display = ''; if (gUs) gUs.style.display = 'none'; } else if (isTema) { if (gJam) gJam.style.display = isPast ? 'none' : ''; if (gUs) gUs.style.display = 'none'; } else { if (isPast) { if (gJam) gJam.style.display = 'none'; if (gUs) gUs.style.display = ''; } else { if (gJam) gJam.style.display = ''; if (gUs) gUs.style.display = 'none'; } } }
