function renderJStats() { var t = 0, the = 0, ev = 0, di = 0, co = 0, oa = 0, vc = 0, ts = 0, mg = 0; jadwalData.forEach(function (r) { t++; var tc = tipeClass(r.tipe); if (tc === 'theater') the++; else if (tc === 'event') ev++; else if (tc === 'digital') di++; else if (tc === 'concert') co++; else if (tc === 'offair') oa++; else if (tc === 'vc') vc++; else if (tc === 'two-shoot') ts++; else if (tc === 'mg') mg++; }); document.getElementById('statTotal').textContent = t; document.getElementById('statTheater').textContent = the; document.getElementById('statEvent').textContent = ev; document.getElementById('statDigital').textContent = di; document.getElementById('statConcert').textContent = co; document.getElementById('statOffair').textContent = oa; document.getElementById('statVc').textContent = vc; document.getElementById('stat2shoot').textContent = ts; document.getElementById('statMg').textContent = mg; }
function getSortedJadwal() { var s = (document.getElementById('searchJ').value || '').toLowerCase(); var f = jadwalData.filter(function (r) { return !s || r.nama.toLowerCase().indexOf(s) !== -1 || r.tanggal.toLowerCase().indexOf(s) !== -1 || tipeLabel(r.tipe).toLowerCase().indexOf(s) !== -1; }); f.sort(function (a, b) { return parseIDDate(b.tanggal) - parseIDDate(a.tanggal); }); return f; }
function applyJadwalView() { var isF = jadwalMode === 'full'; document.getElementById('jadwalHome').classList.toggle('j-hide', isF); document.getElementById('jadwalBack').classList.toggle('j-hide', !isF); renderJadwalTable(); }
function renderJadwalTable() { var f = getSortedJadwal(), isS = !!(document.getElementById('searchJ').value || '').trim(); if (isS && jadwalMode === 'preview') jadwalMode = 'full'; if (!f.length) { document.getElementById('jadwalBody').innerHTML = '<tr class="empty-row"><td colspan="8">' + (isS ? 'Tidak ditemukan' : 'Belum ada data') + '</td></tr>'; document.getElementById('jadwalFooter').innerHTML = ''; return; } if (jadwalMode === 'preview') { document.getElementById('jadwalBody').innerHTML = buildJRows(f.slice(0, 5), 1); document.getElementById('jadwalFooter').innerHTML = f.length > 5 ? '<div class="show-more-bar"><button class="show-more-btn" onclick="enterJadwalFull()">Lihat Selengkapnya</button></div>' : ''; } else { var tp = Math.max(1, Math.ceil(f.length / jadwalPageSize)); if (jadwalPage > tp) jadwalPage = tp; var s = (jadwalPage - 1) * jadwalPageSize, e = Math.min(s + jadwalPageSize, f.length); document.getElementById('jadwalBody').innerHTML = buildJRows(f.slice(s, e), s + 1); document.getElementById('jadwalFooter').innerHTML = buildPgHTML(jadwalPage, tp, f.length, s + 1, e, 'goJadwalPage', 'setJadwalPageSize', jadwalPageSize); } }
function buildJRows(items, no) { var h = ''; for (var i = 0; i < items.length; i++) { var r = items[i], ft = isFuture(r.tanggal), tc = tipeClass(r.tipe), isTema = isTemaType(tc); h += '<tr><td style="color:var(--muted)">' + (no + i) + '</td><td style="font-weight:500">' + escHtml(r.nama) + '</td><td><span class="type-badge ' + tc + '">' + tipeLabel(r.tipe) + '</span></td><td>' + escHtml(r.tanggal) + '</td>'; var soLinkCell = '<td>-</td>'; if (isTema && ft) { var soHtml = r.so ? '<div style="font-size:.76rem;font-weight:600;color:var(--red)">Sold Out</div>' : '<div style="font-size:.68rem;font-weight:600;color:var(--green)">Tersedia</div>'; var linkHtml = r.link ? '<a href="' + escAttr(r.link) + '" target="_blank" class="buy-link"><svg viewBox="0 0 24 24"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"/><polyline points="15 3 21 3 21 9"/><line x1="10" y1="14" x2="21" y2="3"/></svg> Beli Tiket</a>' : '<div style="font-size:.68rem;color:var(--muted)">-</div>'; soLinkCell = '<td>' + soHtml + linkHtml + '</td>'; } h += soLinkCell; var jc = ft ? escHtml(r.jam) : (r.unitSong || r.unit_song ? '<div class="unit-song-label">' + escHtml(r.unitSong || r.unit_song).replace(/\n/g, '<br>') + '</div>' : '<div class="unit-song-empty" onclick="openEditJ(\'' + r.id + '\')">Unit song belum diisi</div>'); h += '<td>' + jc + '</td><td><span class="status-dot ' + (ft ? 'upcoming' : 'done') + '"></span>' + (ft ? 'Mendatang' : 'Selesai') + '</td><td><div class="table-actions"><button class="tbl-btn" onclick="openEditJ(\'' + r.id + '\')" title="Edit"><svg viewBox="0 0 24 24"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg></button><button class="tbl-btn del" onclick="openDelete(\'' + r.id + '\',\'Jadwal\')" title="Hapus"><svg viewBox="0 0 24 24"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg></button></div></td></tr>'; } return h; }
