function addJadwal() { var btn = document.getElementById('addJBtn'); if (btn.disabled) return; btn.disabled = true; btn.textContent = 'Menyimpan...'; var n = document.getElementById('fNama').value.trim(), t = document.getElementById('fTipe').value, d = document.getElementById('fTanggal').value, j = document.getElementById('fJam').value, ds = document.getElementById('fDesc').value.trim(), us = document.getElementById('fUnitSong').value.trim(), so = document.getElementById('fSo').value.trim(), lk = document.getElementById('fLink').value.trim(); if (!n || !d) { toast('Nama dan tanggal wajib diisi', 'error'); btn.disabled = false; btn.textContent = 'Tambah'; return; } apiPost({ action: 'add', nama: n, tipe: t, deskripsi: ds, tanggal: toIDDate(d), jam: j ? j + ' WIB' : '', unitSong: us, so: so, link: lk }).then(function (r) { if (r.success) { toast('Ditambahkan', 'success'); if (document.getElementById('quickJ').checked) document.getElementById('fTanggal').value = ''; else resetJForm(); jadwalMode = 'preview'; refreshJadwal(); } else toast('Gagal', 'error'); }).catch(function () { toast('Gagal', 'error'); }).finally(function () { btn.disabled = false; btn.textContent = 'Tambah'; }); }
function resetJForm() { document.getElementById('fNama').value = ''; document.getElementById('fTipe').value = 'theater'; document.getElementById('fTanggal').value = ''; document.getElementById('fJam').value = '14:00'; document.getElementById('fUnitSong').value = ''; document.getElementById('fDesc').value = ''; document.getElementById('fSo').value = ''; document.getElementById('fLink').value = ''; updateJadwalFormUI('f'); }
function openEditJ(id) { var r = jadwalData.find(function (x) { return x.id === id; }); if (!r) return; editingJId = id; document.getElementById('eNama').value = r.nama || ''; var selVal = tipeClass(r.tipe); if (selVal === 'teater') selVal = 'theater'; document.getElementById('eTipe').value = selVal; document.getElementById('eTanggal').value = fromIDDate(r.tanggal); document.getElementById('eJam').value = extractTime(r.jam); document.getElementById('eDesc').value = r.deskripsi || ''; document.getElementById('eUnitSong').value = r.unitSong || r.unit_song || ''; document.getElementById('eSo').value = r.so || ''; document.getElementById('eLink').value = r.link || ''; updateJadwalFormUI('e'); openModal('editJModal'); }
