function refreshGaleri() { document.getElementById('galeriTableWrap').innerHTML = '<div style="padding:40px;text-align:center"><div class="spinner"></div><br><span style="color:var(--muted)">Memuat...</span></div>'; apiGet('readGallery').then(function (d) { galeriData = d; var t = 0, ra = 0, rv = 0, al = {}; galeriData.forEach(function (r) { t++; if (r.folder === 'ralyne') ra++; else rv++; al[r.folder + '|' + r.album] = 1; }); document.getElementById('gStatTotal').textContent = t; document.getElementById('gStatRalyne').textContent = ra; document.getElementById('gStatRalvandra').textContent = rv; document.getElementById('gStatAlbum').textContent = Object.keys(al).length; galeriMode = 'preview'; galeriPage = 1; galeriCurrentFolder = null; applyGaleriView(); updateDashboardCounts(); }).catch(function () { document.getElementById('galeriTableWrap').innerHTML = '<div style="padding:40px;text-align:center;color:var(--red)">Gagal memuat</div>'; }); }
function getFolderGroups(sq) { var groups = {}, search = (sq || '').toLowerCase(); galeriData.forEach(function (r) { var k = r.folder + '|' + r.album; if (!groups[k]) groups[k] = { folder: r.folder, album: r.album, label: r.label || r.album, count: 0, firstSrc: r.src }; groups[k].count++; if (!groups[k].firstSrc && r.src) groups[k].firstSrc = r.src; }); var result = Object.values(groups); if (search) result = result.filter(function (g) { return g.label.toLowerCase().indexOf(search) !== -1 || g.album.toLowerCase().indexOf(search) !== -1; }); result.sort(function (a, b) { if (a.folder !== b.folder) return a.folder < b.folder ? -1 : 1; return a.label.toLowerCase().localeCompare(b.label.toLowerCase()); }); return result; }
