function applyGaleriView() { var isF = galeriMode === 'full' || galeriMode === 'detail'; document.getElementById('galeriHome').classList.toggle('j-hide', isF); document.getElementById('galeriBack').classList.toggle('j-hide', !isF); document.getElementById('galeriDetailBar').classList.toggle('j-hide', galeriMode !== 'detail'); renderGaleriTable(); }
function galeriGoBack() { if (galeriMode === 'detail') { galeriMode = 'preview'; galeriCurrentFolder = null; galeriPage = 1; } else { galeriMode = 'preview'; galeriPage = 1; } document.getElementById('searchG').value = ''; applyGaleriView(); }
