function getFilteredFunfact() { var s = (document.getElementById('searchFf').value || '').toLowerCase(); return funfactData.filter(function (r) { return !s || (r.fakta || r.text || r.fact || '').toLowerCase().indexOf(s) !== -1; }); }
function applyFunfactView() { var isF = funfactMode === 'full'; document.getElementById('funfactHome').classList.toggle('j-hide', isF); document.getElementById('funfactBack').classList.toggle('j-hide', !isF); renderFunfactTable(); }
function renderFunfactTable() { var f = getFilteredFunfact(), isS = !!(document.getElementById('searchFf').value || '').trim(); if (isS && funfactMode === 'preview') funfactMode = 'full'; if (!f.length) { document.getElementById('funfactBody').innerHTML = '<tr class="empty-row"><td colspan="3">' + (isS ? 'Tidak ditemukan' : 'Belum ada fun fact') + '</td></tr>'; document.getElementById('funfactFooter').innerHTML = ''; return; } if (funfactMode === 'preview') { document.getElementById('funfactBody').innerHTML = buildFfRows(f.slice(0, 5), 1); document.getElementById('funfactFooter').innerHTML = f.length > 5 ? '<div class="show-more-bar"><button class="show-more-btn" onclick="funfactMode=\'full\';funfactPage=1;applyFunfactView();">Lihat Selengkapnya</button></div>' : ''; } else { var tp = Math.max(1, Math.ceil(f.length / funfactPageSize)); if (funfactPage > tp) funfactPage = tp; var s = (funfactPage - 1) * funfactPageSize, e = Math.min(s + funfactPageSize, f.length); document.getElementById('funfactBody').innerHTML = buildFfRows(f.slice(s, e), s + 1); document.getElementById('funfactFooter').innerHTML = buildPgHTML(funfactPage, tp, f.length, s + 1, e, 'goFunfactPage', 'setFunfactPageSize', funfactPageSize); } }
function buildFfRows(items, no) { var h = ''; for (var i = 0; i < items.length; i++) { var r = items[i]; var txt = r.fakta || r.text || r.fact || '-'; h += '<tr><td style="color:var(--muted)">' + (no + i) + '</td><td style="font-size:.84rem;line-height:1.5">' + escHtml(txt) + '</td><td><div class="table-actions"><button class="tbl-btn" onclick="openEditFf(\'' + r.id + '\')" title="Edit"><svg viewBox="0 0 24 24"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg></button><button class="tbl-btn del" onclick="openDeleteFf(\'' + r.id + '\')" title="Hapus"><svg viewBox="0 0 24 24"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg></button></div></td></tr>'; } return h; }
function exitFunfactFull() { funfactMode = 'preview'; document.getElementById('searchFf').value = ''; applyFunfactView(); }
function onFunfactSearch() { var isS = !!(document.getElementById('searchFf').value || '').trim(); if (isS && funfactMode === 'preview') { funfactMode = 'full'; applyFunfactView(); } else renderFunfactTable(); }
function goFunfactPage(p) { var f = getFilteredFunfact(); if (p < 1 || p > Math.max(1, Math.ceil(f.length / funfactPageSize))) return; funfactPage = p; renderFunfactTable(); }
function setFunfactPageSize(v) { funfactPageSize = v; funfactPage = 1; renderFunfactTable(); }
function addFunfact() { var btn = document.getElementById('addFfBtn'); if (btn.disabled) return; btn.disabled = true; btn.textContent = 'Menyimpan...'; var fakta = document.getElementById('ffFakta').value.trim(); if (!fakta) { toast('Fakta wajib diisi', 'error'); btn.disabled = false; btn.textContent = 'Tambah'; return; } apiPost({ action: 'addFunfact', fakta: fakta }).then(function (r) { if (r.success) { toast('Fun fact ditambahkan', 'success'); if (document.getElementById('quickFf').checked) { document.getElementById('ffFakta').value = ''; } else resetFfForm(); funfactMode = 'preview'; refreshFunfact(); } else toast('Gagal', 'error'); }).catch(function () { toast('Gagal', 'error'); }).finally(function () { btn.disabled = false; btn.textContent = 'Tambah'; }); }
function resetFfForm() { document.getElementById('ffFakta').value = ''; }
function openEditFf(id) { var r = funfactData.find(function (x) { return x.id === id; }); if (!r) return; editingFfId = id; document.getElementById('effFakta').value = r.fakta || r.text || r.fact || ''; openModal('editFfModal'); }
function saveEditFf() { var btn = document.querySelector('#editFfModal .btn-save'); if (btn.disabled) return; btn.disabled = true; btn.textContent = 'Menyimpan...'; var fakta = document.getElementById('effFakta').value.trim(); if (!fakta) { toast('Fakta wajib diisi', 'error'); btn.disabled = false; btn.textContent = 'Simpan'; return; } apiPost({ action: 'editFunfact', id: editingFfId, fakta: fakta }).then(function (r) { if (r.success) { toast('Fun fact diupdate', 'success'); closeModal('editFfModal'); refreshFunfact(); } else toast('Gagal', 'error'); }).catch(function () { toast('Gagal', 'error'); }).finally(function () { btn.disabled = false; btn.textContent = 'Simpan'; }); }
function openDeleteFf(id) { var r = funfactData.find(function (x) { return x.id === id; }); var txt = r ? (r.fakta || r.text || r.fact || '') : ''; var shortTxt = txt.length > 40 ? txt.substring(0, 40) + '...' : txt; document.getElementById('deleteMsg').innerHTML = 'Hapus fun fact "<strong style="color:var(--text)">' + escHtml(shortTxt) + '</strong>"?'; var btn = document.getElementById('deleteConfirmBtn'); btn.textContent = 'Hapus'; btn.className = 'btn-confirm'; btn.disabled = false; btn.onclick = function () { if (btn.disabled) return; btn.disabled = true; btn.textContent = 'Menghapus...'; apiPost({ action: 'deleteFunfact', id: id }).then(function (r) { if (r.success) { toast('Fun fact dihapus', 'success'); closeModal('deleteModal'); refreshFunfact(); } else { toast('Gagal', 'error'); btn.disabled = false; btn.textContent = 'Hapus'; } }).catch(function () { toast('Gagal', 'error'); btn.disabled = false; btn.textContent = 'Hapus'; }); }; openModal('deleteModal'); }
function openBatchFunfactModal() { document.getElementById('bffFacts').value = ''; openModal('batchFunfactModal'); }
function submitBatchFunfact() { var btn = document.getElementById('batchFfBtn'); if (btn.disabled) return; btn.disabled = true; btn.textContent = 'Menyimpan...'; var raw = document.getElementById('bffFacts').value.trim(); if (!raw) { toast('Masukkan daftar fun fact', 'error'); btn.disabled = false; btn.textContent = 'Tambah Semua'; return; } var lines = raw.split('\n').map(function (s) { return s.trim(); }).filter(function (s) { return s !== ''; }); if (!lines.length) { toast('Tidak ada fun fact valid', 'error'); btn.disabled = false; btn.textContent = 'Tambah Semua'; return; } var chain = Promise.resolve(); var ok = 0, fail = 0; lines.forEach(function (fakta) { chain = chain.then(function () { return apiPost({ action: 'addFunfact', fakta: fakta }).then(function (r) { if (r.success) ok++; else fail++; }).catch(function () { fail++; }); }); }); chain.then(function () { if (ok > 0) toast(ok + ' fun fact ditambahkan', 'success'); if (fail > 0) toast(fail + ' gagal ditambahkan', 'error'); closeModal('batchFunfactModal'); refreshFunfact(); }).finally(function () { btn.disabled = false; btn.textContent = 'Tambah Semua'; }); }

function openDelete(id, label) { document.getElementById('deleteMsg').innerHTML = 'Hapus data <strong style="color:var(--text)">' + escHtml(label) + '</strong>?'; var btn = document.getElementById('deleteConfirmBtn'); btn.textContent = 'Hapus'; btn.className = 'btn-confirm'; btn.disabled = false; btn.onclick = function () { if (btn.disabled) return; btn.disabled = true; btn.textContent = 'Menghapus...'; apiPost({ action: 'delete', id: id }).then(function (r) { if (r.success) { toast('Dihapus', 'success'); closeModal('deleteModal'); refreshJadwal(); } else { toast('Gagal', 'error'); btn.disabled = false; btn.textContent = 'Hapus'; } }).catch(function () { toast('Gagal', 'error'); btn.disabled = false; btn.textContent = 'Hapus'; }); }; openModal('deleteModal'); }

function openModal(id) { document.getElementById(id).classList.add('active'); }
function closeModal(id) { document.getElementById(id).classList.remove('active'); }
document.querySelectorAll('.modal-overlay').forEach(function (el) { el.addEventListener('click', function (e) { if (e.target === el) el.classList.remove('active'); }); });

var toastTimers = {};
function toast(msg, type) { var key = msg + '|' + type; if (toastTimers[key]) return; toastTimers[key] = true; setTimeout(function () { delete toastTimers[key]; }, 4000); var t = document.createElement('div'); t.className = 'toast ' + (type || 'info'); t.textContent = msg; document.getElementById('toastBox').appendChild(t); setTimeout(function () { t.classList.add('show'); }, 30); setTimeout(function () { t.classList.remove('show'); setTimeout(function () { t.remove(); }, 400); }, 3500); }

(function () { var ids = ['gLabel', 'gAlt', 'egLabel', 'egAlt']; function enforceLock() { ids.forEach(function (id) { var el = document.getElementById(id); if (!el) return; if (el.classList.contains('locked')) { el.setAttribute('readonly', ''); el.setAttribute('tabindex', '-1'); el.style.pointerEvents = 'none'; el.style.userSelect = 'none'; } else { el.removeAttribute('readonly'); el.removeAttribute('tabindex'); el.style.pointerEvents = ''; el.style.userSelect = ''; } }); } enforceLock(); setInterval(enforceLock, 500); })();

(function () { var t = todayStr(); var vTgl = document.getElementById('vTanggal'); if (vTgl) vTgl.value = t; })();